type DisableMode int //gd:CollisionObject3D.DisableMode

const (
	// When [Node.ProcessMode] is set to [Node.ProcessModeDisabled], remove from the physics simulation to stop all physics interactions with this [CollisionObject3D].
	//
	// Automatically re-added to the physics simulation when the [Node] is processed again.
	//
	// [CollisionObject3D]: https://pkg.go.dev/graphics.gd/classdb/CollisionObject3D
	// [Node]: https://pkg.go.dev/graphics.gd/classdb/Node
	// [Node.ProcessMode]: https://pkg.go.dev/graphics.gd/classdb/Node#Instance.ProcessMode
	DisableModeRemove DisableMode = 0
	// When [Node.ProcessMode] is set to [Node.ProcessModeDisabled], make the body static. Doesn't affect [Area3D]. [PhysicsBody3D] can't be affected by forces or other bodies while static.
	//
	// Automatically set [PhysicsBody3D] back to its original mode when the [Node] is processed again.
	//
	// [Area3D]: https://pkg.go.dev/graphics.gd/classdb/Area3D
	// [Node]: https://pkg.go.dev/graphics.gd/classdb/Node
	// [Node.ProcessMode]: https://pkg.go.dev/graphics.gd/classdb/Node#Instance.ProcessMode
	// [PhysicsBody3D]: https://pkg.go.dev/graphics.gd/classdb/PhysicsBody3D
	DisableModeMakeStatic DisableMode = 1
	// When [Node.ProcessMode] is set to [Node.ProcessModeDisabled], do not affect the physics simulation.
	//
	// [Node.ProcessMode]: https://pkg.go.dev/graphics.gd/classdb/Node#Instance.ProcessMode
	DisableModeKeepActive DisableMode = 2
)
